BEGIN TRANSACTION;
CREATE TABLE "city_summary_table" (
"local_datetime" TIMESTAMP,
  "kota_kabupaten" TEXT,
  "avg_temperature_c" REAL,
  "avg_humidity_ptg" REAL,
  "avg_heat_index_c" REAL
);
CREATE TABLE "ward_boundary_table_simplified" (
"adm4" TEXT,
  "geometry" TEXT
);
CREATE TABLE "ward_weather_table" (
"adm4" TEXT,
  "desa_kelurahan" TEXT,
  "kecamatan" TEXT,
  "kota_kabupaten" TEXT,
  "provinsi" TEXT,
  "latitude" REAL,
  "longitude" REAL,
  "timezone" TEXT,
  "local_datetime" TEXT,
  "temperature_c" REAL,
  "humidity_ptg" REAL,
  "heat_index_c" REAL,
  "risk_level" TEXT,
  "weather_desc" TEXT,
  "fetched_at" TEXT
);
CREATE INDEX idx_weather_time
            ON ward_weather_table(local_datetime);
CREATE INDEX idx_weather_region_time
            ON ward_weather_table(adm4, local_datetime);
CREATE INDEX idx_city_summary_time
            ON city_summary_table (local_datetime);
COMMIT;
